// 1. Palabras clave para el filtrado temático strico
const palabrasClave = [
  'guerra', 'conflicto', 'elecciones', 'tratado', 'sanciones', 'cumbre', 'alianza', 'otan',
  'ia', 'inteligencia artificial', 'software', 'ciberseguridad', 'chips', 'tecnología', 'tech',
  'mercado', 'inflación', 'tasas', 'banco', 'acciones', 'petróleo', 'dólar', 'economía', 'finanzas', 'euro'
];

const todosLosItems = $input.all();
const conteoFuentes = {};
const noticiasFiltradas = [];

for (const item of todosLosItems) {
  const titulo = (item.json.title || '').toLowerCase();
  const contenido = (item.json.content || item.json.contentSnippet || item.json.summary || '').toLowerCase();

  // Extraemos el dominio base para identificar la fuente de forma limpia
  const urlRaw = item.json.link ? item.json.link.toLowerCase() : '';
  let fuente = 'Desconocido';

  if (urlRaw.includes('bbc')) {
    fuente = 'BBC';
  } else if (urlRaw.includes('elmundo')) {
    fuente = 'El Mundo';
  }

  // Control estricto de cuota: Máximo 6 artículos por medio oficial
  if (conteoFuentes[fuente] >= 6) continue;

  // Validación de relevancia por palabras clave
  const esRelevante = palabrasClave.some(palabra => titulo.includes(palabra) || contenido.includes(palabra));

  if (esRelevante) {
    if (!conteoFuentes[fuente]) conteoFuentes[fuente] = 0;

    conteoFuentes[fuente]++;
    noticiasFiltradas.push(`- Título: ${item.json.title}\n  Fuente: ${fuente}\n  Link: ${item.json.link}`);
  }
}

// Consolidación de salida en formato String plano optimizado para LLMs
const listaFinalTexto = noticiasFiltradas.join('\n\n');

return [{ json: { listaNoticias: listaFinalTexto, totalProcesadas: noticiasFiltradas.length } }];

// 1. Obtenemos el texto que generó la IA con la ruta directa del item
const textoGemini = $input.item.json.output[0].content[0].text;

// 2. Lo convertimos en objeto JSON
const reporteLimpio = JSON.parse(textoGemini);
const filasParaGoogleSheets = [];

// 3. Recorremos las categorías
for (let seccion of reporteLimpio.sections) {

    // Recorremos CADA noticia/análisis individual dentro de esa categoría
    if (seccion.analysis && seccion.analysis.length > 0) {
        for (let bloqueAnalisis of seccion.analysis) {

            const resumenTexto = bloqueAnalisis.summary;

            // Extraemos el link único de forma limpia y sin espacios fantasmas
            let linkUnico = "";
            if (bloqueAnalisis.sources && bloqueAnalisis.sources.length > 0) {
                linkUnico = bloqueAnalisis.sources[0].link.trim();
            }

            // 4. Creamos la fila perfecta e independiente
            filasParaGoogleSheets.push({
                json: {
                    categoria: seccion.category,
                    resumen: resumenTexto,
                    fuentes: linkUnico
                }
            });
        }
    }
}

// Devolvemos los datos listos para Google Sheets
return filasParaGoogleSheets;

// Inicializamos la variable para acumular el texto
let texto_final = "";

// 1. Obtenemos todos los items de entrada de forma moderna
const items = $input.all();

// 2. Recorremos cada uno de los reportes que vienen de la IA
for (let i = 0; i < items.length; i++) {
    // Extraemos el texto limpio usando la ruta exacta de la nueva interfaz
    let noticia = items[i].json.output[0].content[0].text;

    // Lo suma al reporte final separando cada noticia con una línea
    texto_final += noticia + "\n\n===================================\n\n";
}

// 3. Devolvemos un solo bloque de texto consolidado
return [{
    json: {
        reporte_completo: texto_final
    }
}];

